parameters.functionCode:
const data = $input.first().json;
const webhook = $node['Webhook: LP Generate'].json.body;

try {
  const fullResponse = data.content[0].text;

  // Split HTML from section data
  let htmlContent = fullResponse;
  let sectionData = [];

  const separatorIndex = fullResponse.indexOf('---SECTIONS---');
  if (separatorIndex !== -1) {
    htmlContent = fullResponse.substring(0, separatorIndex).trim();
    const sectionJson = fullResponse.substring(separatorIndex + 14).trim();
    try {
      sectionData = JSON.parse(sectionJson.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
    } catch(e) { sectionData = []; }
  }

  // Clean up HTML if wrapped in markdown code blocks
  htmlContent = htmlContent.replace(/^```html\n?/g, '').replace(/\n?```$/g, '').trim();

  return [{
    json: {
      brand_id: webhook.brand_id,
      offer_id: webhook.offer_id,
      swipe_id: webhook.swipe_id,
      page_type: webhook.page_type,
      html_content: htmlContent,
      section_data: sectionData,
      generation_config: {
        awareness_level: webhook.awareness_level,
        tone: webhook.tone,
        extra_instructions: webhook.extra_instructions
      },
      status: 'draft',
      title: `${webhook.page_type} — Generated ${new Date().toISOString().split('T')[0]}`
    }
  }];
} catch (e) {
  return [{
    json: {
      brand_id: webhook.brand_id,
      offer_id: webhook.offer_id,
      swipe_id: webhook.swipe_id,
      page_type: webhook.page_type,
      html_content: '<html><body><h1>Generation failed</h1><p>' + e.message + '</p></body></html>',
      section_data: [],
      status: 'draft',
      title: 'Failed generation'
    }
  }];
}
